const data = $input.first().json.body;
const signals = data.signals || [];

const formatSignals = (level) => {
  const group = signals.filter(s => s.impact_level === level);
  if (!group.length) return '';
  let out = `<h3 style="color:${level==='High'?'#c0392b':level==='Medium'?'#d17a00':'#2d8a4e'}">${level} Impact</h3>`;
  group.forEach(s => {
    out += `<div style="border-left:3px solid ${level==='High'?'#c0392b':level==='Medium'?'#d17a00':'#2d8a4e'};padding:10px 14px;margin-bottom:12px;background:#fafafa">`;
    out += `<strong>${s.title || ''}</strong>`;
    if (s.url) out += ` <a href="${s.url}">[source]</a>`;
    out += `<br/><span style="color:#666;font-size:13px">${s.impact_summary || ''}</span>`;
    if (s.strategic_link) out += `<br/><span style="color:#999;font-size:12px">→ ${s.strategic_link}</span>`;
    if (s.confidence) out += `<span style="float:right;color:#999;font-size:12px">${s.confidence}/10</span>`;
    out += '</div>';
  });
  return out;
};

let takeaway = data.executive_takeaway || '';
if (takeaway.includes('── EXECUTIVE TAKEAWAY')) {
  takeaway = takeaway.split('── EXECUTIVE TAKEAWAY')[1].replace(/─+/g,'').trim();
}

const html = `
<!DOCTYPE html>
<html>
<head><meta charset="utf-8"><style>
  body { font-family: Georgia, serif; max-width: 680px; margin: 40px auto; color: #1a1a1a; }
  h1 { font-size: 22px; border-bottom: 2px solid #1a1a1a; padding-bottom: 8px; }
  .meta { color: #666; font-size: 13px; margin-bottom: 24px; }
  .takeaway { background: #1a1a1a; color: white; padding: 16px 20px; border-radius: 4px; margin-top: 24px; }
  .takeaway-label { font-size: 11px; letter-spacing: 0.1em; text-transform: uppercase; opacity: 0.5; margin-bottom: 6px; }
  .stats { display: flex; gap: 24px; margin-bottom: 24px; }
  .stat { text-align: center; }
  .stat-value { font-size: 28px; font-weight: 300; }
  .stat-label { font-size: 11px; text-transform: uppercase; color: #999; }
</style></head>
<body>
  <h1>Strategic Radar — ${data.competitor}</h1>
  <div class="meta">${data.intelligence_type} · Last ${data.time_range_days} days · ${data.generated_at ? new Date(data.generated_at).toLocaleDateString('en-GB') : ''} · ${data.llm_calls_made || 0}/7 LLM calls · ${data.elapsed_seconds || 0}s</div>
  <div class="stats">
    <div class="stat"><div class="stat-value" style="color:#c0392b">${signals.filter(s=>s.impact_level==='High').length}</div><div class="stat-label">High</div></div>
    <div class="stat"><div class="stat-value" style="color:#d17a00">${signals.filter(s=>s.impact_level==='Medium').length}</div><div class="stat-label">Medium</div></div>
    <div class="stat"><div class="stat-value" style="color:#2d8a4e">${signals.filter(s=>s.impact_level==='Low').length}</div><div class="stat-label">Low</div></div>
    <div class="stat"><div class="stat-value">${signals.length}</div><div class="stat-label">Total</div></div>
  </div>
  ${formatSignals('High')}
  ${formatSignals('Medium')}
  ${formatSignals('Low')}
  <div class="takeaway">
    <div class="takeaway-label">Executive Takeaway</div>
    <p style="margin:0;line-height:1.6;font-size:14px">${takeaway}</p>
  </div>
</body>
</html>`;

return [{ json: { html, subject: `Strategic Radar — ${data.competitor} (${data.intelligence_type})`, to: data.notify_email || '' } }];
